// Prepare Final Reply v5: Merge rule-based or AI output into final reply
try {
  const data = $input.first().json;
  let replyText = '';
  let senderPsid = data.senderPsid || '';

  // Priority order for reply text
  if (data.replyText && data.replyText.length > 0) {
    replyText = data.replyText;
  } else if (data.output && typeof data.output === 'string' && data.output.length > 0) {
    replyText = data.output;
  } else if (data.text && typeof data.text === 'string' && data.text.length > 0) {
    replyText = data.text;
  } else if (data.response && typeof data.response === 'string' && data.response.length > 0) {
    replyText = data.response;
  } else {
    replyText = 'I apologize for the inconvenience. Please type "human" and our team will assist you directly.';
  }

  // Get senderPsid from Decision Engine if not present
  if (!senderPsid) {
    try { senderPsid = $('Decision Engine v5').first().json.senderPsid || ''; } catch(e) {}
  }

  // Truncate to Messenger limit
  if (replyText.length > 1950) {
    replyText = replyText.substring(0, 1947) + '...';
  }

  return [{ json: {
    senderPsid,
    replyText,
    needsHumanSupport: data.needsHumanSupport || false,
    telegramAlertText: data.telegramAlertText || '',
    skipSend: data.skipSend || false,
    memoryUpdate: data.memoryUpdate || {},
    intent: data.intent || 'unknown',
    route: data.route || 'unknown',
    aiUsed: data.aiUsed || false,
    messageMid: data.messageMid || ''
  }}];
} catch (err) {
  return [{ json: {
    senderPsid: '',
    replyText: 'Something went wrong. Type "human" for support.',
    needsHumanSupport: true,
    telegramAlertText: 'ERROR in Prepare Final Reply: ' + err.message,
    skipSend: false,
    memoryUpdate: {},
    intent: 'error',
    route: 'error',
    aiUsed: false,
    messageMid: ''
  }}];
}

// Update Memory + Log v5: Persist memory updates to workflow static data
try {
  const data = $input.first().json;
  const senderPsid = data.senderPsid;
  const memoryUpdate = data.memoryUpdate || {};

  if (senderPsid && Object.keys(memoryUpdate).length > 0) {
    const staticData = $getWorkflowStaticData('global');
    const memKey = `mem_${senderPsid}`;
    if (!staticData[memKey]) staticData[memKey] = {};

    // Apply updates
    for (const [key, value] of Object.entries(memoryUpdate)) {
      staticData[memKey][key] = value;
    }
    staticData[memKey].lastActive = Date.now();
    staticData[memKey].lastIntent = data.intent || staticData[memKey].lastIntent;

    // Clean old memory entries (>7 days)
    const sevenDays = 7 * 24 * 60 * 60 * 1000;
    const now = Date.now();
    for (const key of Object.keys(staticData)) {
      if (key.startsWith('mem_') && staticData[key].lastActive && (now - staticData[key].lastActive > sevenDays)) {
        delete staticData[key];
      }
    }
  }

  return [{ json: data }];
} catch (err) {
  // Memory update failure should not block the reply
  return [{ json: $input.first().json }];
}

// Mark Processed v5: Mark messageMid as processed after successful send
try {
  const data = $input.first().json;
  const messageMid = data.messageMid || $('Decision Engine v5').first()?.json?.messageMid;

  if (messageMid) {
    const staticData = $getWorkflowStaticData('global');
    if (!staticData.processedMids) staticData.processedMids = {};
    staticData.processedMids[messageMid] = Date.now();
  }

  return [{ json: data }];
} catch (err) {
  return [{ json: $input.first().json }];
}

// Prepare Telegram Alert v5: Format alert message for Telegram
try {
  const data = $input.first().json;
  const timestamp = new Date().toISOString().replace('T', ' ').substring(0, 19);
  const memorySummary = JSON.stringify(data.memoryUpdate || {}).substring(0, 200);

  const telegramMessage = `<b>HUMAN SUPPORT NEEDED</b>\n\n` +
    `<b>PSID:</b> ${data.senderPsid || 'unknown'}\n` +
    `<b>Message ID:</b> ${data.messageMid || 'N/A'}\n` +
    `<b>Customer Message:</b> ${(data.customerMessage || data.replyText || '').substring(0, 300)}\n` +
    `<b>Language:</b> ${data.languageStyle || 'unknown'}\n` +
    `<b>Intent:</b> ${data.intent || 'unknown'}\n` +
    `<b>Confidence:</b> ${data.confidence || 'unknown'}\n` +
    `<b>Reason:</b> ${data.telegramAlertText || 'human_support_triggered'}\n` +
    `<b>Memory:</b> ${memorySummary}\n` +
    `<b>Time:</b> ${timestamp}`;

  return [{ json: { ...data, telegramMessage } }];
} catch (err) {
  const data = $input.first()?.json || {};
  return [{ json: { ...data, telegramMessage: `ALERT ERROR: ${err.message}\nPSID: ${data.senderPsid || 'unknown'}` } }];
}
